var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"하아… 하…","JPN":"はあ……は……","ENG":"*Huff* *Huff*","TWN":"哈啊……哈啊……"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어때요? 당신이 불러낸 것들, 전부 쓰러트렸다고요.","JPN":"どうですか？　あなたが呼び出したの、全部倒しましたよ。","ENG":"How's that? I've taken down everything you summoned.","TWN":"怎麼樣？你召喚出來的那些東西，已經全都被擊倒了！"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"…그러네. 우릴 상대할수록 더 강해지고 있어.","JPN":"……そうね。私たちの相手をするたび強くなっている。","ENG":"...I see. The more you face us, the stronger you get.","TWN":"……確實，越是和我們戰鬥，它們就變得越強。"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"원리가 뭐지? 놈들의 힘을 흡수한 거야?","JPN":"原理はなに？　やつらの力を吸収したの？","ENG":"How are you doing that? Did you absorb their power?","TWN":"是什麼原理呢？是吸收了那些傢伙的力量嗎？"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"성장하는 거에요. 어른으로서.","JPN":"成長しています。大人として。","ENG":"I'm growing up, as an adult.","TWN":"這是在成長，慢慢變成大人的過程。"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"남의 것을 훔쳐서 강해지고 똑똑해지는 당신은 평생 이걸 이해하지 못하겠죠.","JPN":"他人のものを盗むことで強くなり賢くなるあなたにとって、これは一生理解できません。","ENG":"Someone who steals others' things to grow stronger and smarter will never understand.","TWN":"對於通過掠奪他人，從而變得更強大、更聰明的你來說，可能這一生都無法理解。"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"안 그런가요?","JPN":"違いますか？","ENG":"Isn't that right?","TWN":"不是嗎？"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"내가 처음으로 본 인간은 자신이 원하는 걸 갖기 위해 같은 동족을 해쳤어.","JPN":"私が初めて見た人間は自分が欲しいものを手に入れるために同族を殺した。","ENG":"The first human I saw killed his own kind to get what he wanted.","TWN":"我見過的第一個人類，為了得到自己想要的東西而傷害了同類。"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"더 약한 놈을 이겨서 원하는 걸 갖는다. 간단하잖아?","JPN":"より弱いやつに勝って欲しいものを手に入れる。簡単でしょう？","ENG":"You beat the weaker ones to get what you want. It's simple, right?","TWN":"打敗更弱小的傢伙，從而得到想要的東西，這不是很簡單的道理嗎？"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런 건… 나쁜 짓이에요! 해선 안 되는 거라고요.","JPN":"それは……悪いことです！　やっちゃいけないことです。","ENG":"That's... a bad thing to do! You shouldn't do it.","TWN":"那是不對的！是不該做的事情！"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"상관없어.","JPN":"構わない。","ENG":"It doesn't matter.","TWN":"無所謂。"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"난 그 방식이 마음에 들었거든.","JPN":"私はそのやり方が気に入ったから。","ENG":"I liked that way.","TWN":"我喜歡這種方式。"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"사라졌다…!","JPN":"消えた……！","ENG":"She's gone...!","TWN":"消失了……！"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"니블은 평범한 인간은 손대지 않아. 단지 카운터의 힘을 빼앗을 뿐.","JPN":"ニブルは普通の人には手を出さない。ただカウンターの力を奪うだけ。","ENG":"Nibble doesn't bother with ordinary humans. She just takes the power of Counters.","TWN":"蠶食不會對普通人類動手，只會奪取制裁者的力量。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그건 식물도 마찬가지야.","JPN":"それは植物も同じ。","ENG":"It's the same with plants.","TWN":"植物也是一樣的。"},"stage":{"bg":"ANIV2_03-2","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"양분으로 자란 꽃은 멀쩡했지만, 내 힘으로 자란 덩굴들은 니블이 남긴 바이러스 때문에 시들었으니까.","JPN":"養分で育てた花は平気だったけど、私の力で成長させたツタはニブルが残したウイルスのせいで枯れてしまった。","ENG":"The flowers grown with nutrients were fine, but the vines grown with my power withered because of the virus left by Nibble.","TWN":"依靠養分生長的花朵還活著，但那些依靠我的力量而生長的藤蔓，卻都因蠶食殘留的病毒而枯萎了。"},"stage":{"bg":"ANIV2_03-2","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"틀림없어.","JPN":"間違いない。","ENG":"That must be it.","TWN":"沒錯。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"녀석이 지나간 자리에 핀 꽃은… 시든다!","JPN":"ニブルが通る道に咲いている花は……枯れる！","ENG":"The flowers wither... where she passes!","TWN":"蠶食經過的地方……花朵都會枯萎！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"보였어…!","JPN":"見えた……！","ENG":"I can see her now...!","TWN":"我看到了……！"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이쪽!","JPN":"こっち！","ENG":"This side!","TWN":"這邊！"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"큿?!","JPN":"くっ！？","ENG":"Kgh?!","TWN":"唔？！"},"stage":{"bg":"CITY_BLOSSOM","slots":{"L":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_SURPRISE"},"C":null,"R":null}}}]`);export{e as default};